/**
 * Sets a new location and radius for this circle.
 *
 * @param position Position {@link Vector2} for this circle.
 * @param radius   Circle radius
 */
public void set(Vector2 position, float radius) {
    this.x = position.x;
    this.y = position.y;
    this.radius = radius;
}
